    public static function svg($name, $size = 18, $class = 'icon') {
        $svg = self::$icons[$name] ?? self::$icons['file'];
        $attrs = 'width="' . (int)$size . '" height="' . (int)$size . '" class="' . htmlspecialchars($class) . '" aria-hidden="true"';
        return preg_replace('/<svg /', '<svg ' . $attrs . ' ', $svg, 1);
    }
